// MQTT payload is an array: [ measurements, metadata ]
var data = msg.payload;
if (!Array.isArray(data) || data.length < 2) { return null; }
var m = data[0];      // measurements
var meta = data[1];   // device metadata

// Keep only the numeric measurements we want
var fields = {};
if (m.temperature !== undefined) { fields.temperature = m.temperature; }
if (m.humidity !== undefined)    { fields.humidity = m.humidity; }
if (m.co2 !== undefined)         { fields.co2 = m.co2; }
if (m.illumination !== undefined){ fields.illumination = m.illumination; }

// Tags identify the sensor location
var tags = { room: meta.room || "unknown", building: meta.Building || "unknown" };

// InfluxDB "out" node expects [ fields, tags ]
msg.payload = [fields, tags];
return msg;
